import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "cnfast";
import * as React from "react";

import { CodeCopyButton } from "./code-copy-button";

const codeVariants = cva("font-mono tabular-nums text-foreground", {
  variants: {
    variant: {
      inline: [
        "inline rounded-md border border-neutral-200 bg-neutral-950/[0.04]",
        "px-1.5 py-0.5 text-[0.875em] leading-none",
        "dark:border-white/10 dark:bg-white/10",
      ],
      block: [
        "block max-w-full overflow-x-auto whitespace-pre rounded-lg border border-neutral-200",
        "bg-neutral-50 px-4 py-3 text-sm leading-6 text-neutral-700 shadow-sm",
        "dark:border-white/10 dark:bg-white/5 dark:text-neutral-300",
      ],
    },
    tone: {
      default: "",
      muted: "text-neutral-600 dark:text-neutral-300",
      accent: "border-primary/25 bg-primary/10 text-foreground",
      danger:
        "border-red-600/20 bg-red-600/10 text-red-700 dark:text-red-300",
      success:
        "border-emerald-600/20 bg-emerald-600/10 text-emerald-700 dark:text-emerald-300",
      warning:
        "border-amber-500/25 bg-amber-500/10 text-amber-800 dark:text-amber-300",
    },
  },
  defaultVariants: {
    variant: "inline",
    tone: "default",
  },
});

type CodeProps = React.HTMLAttributes<HTMLElement> &
  VariantProps<typeof codeVariants> & {
    as?: "code" | "pre";
    copiedLabel?: string;
    copyable?: boolean;
    copyButtonClassName?: string;
    copyLabel?: string;
    copyValue?: string;
  };

function getCopyText(children: React.ReactNode): string {
  if (children === null || children === undefined || typeof children === "boolean") {
    return "";
  }

  if (typeof children === "string" || typeof children === "number") {
    return String(children);
  }

  if (Array.isArray(children)) {
    return children.map(getCopyText).join("");
  }

  if (React.isValidElement<{ children?: React.ReactNode }>(children)) {
    return getCopyText(children.props.children);
  }

  return "";
}

function Code({
  as,
  children,
  className,
  copiedLabel,
  copyable = false,
  copyButtonClassName,
  copyLabel,
  copyValue,
  tone,
  variant,
  ...props
}: CodeProps) {
  const Component = as ?? (variant === "block" ? "pre" : "code");
  const resolvedVariant = variant ?? "inline";
  const code = (
    <Component
      data-slot="code"
      className={cn(
        codeVariants({ variant, tone }),
        copyable && resolvedVariant === "block" ? "pr-12" : "",
        className,
      )}
      {...props}
    >
      {children}
    </Component>
  );

  if (!copyable) return code;

  return resolvedVariant === "block" ? (
    <div data-slot="code-copy-wrapper" className="group/code relative max-w-full">
      {code}
      <CodeCopyButton
        className={copyButtonClassName}
        copiedLabel={copiedLabel}
        copyLabel={copyLabel}
        value={copyValue ?? getCopyText(children)}
      />
    </div>
  ) : (
    <span
      data-slot="code-copy-wrapper"
      className="inline-flex items-center gap-[0.25em] align-baseline"
    >
      {code}
      <CodeCopyButton
        className={copyButtonClassName}
        copiedLabel={copiedLabel}
        copyLabel={copyLabel}
        placement="inline"
        value={copyValue ?? getCopyText(children)}
      />
    </span>
  );
}

export { Code, CodeCopyButton, codeVariants };

"use client";

import { cn } from "cnfast";
import * as React from "react";

type CodeCopyButtonProps = React.ButtonHTMLAttributes<HTMLButtonElement> & {
  copiedLabel?: string;
  copyLabel?: string;
  placement?: "block" | "inline";
  timeout?: number;
  value: string;
};

function CopyIcon({ className }: { className?: string }) {
  return (
    <svg
      aria-hidden="true"
      className={className}
      fill="none"
      viewBox="0 0 16 16"
    >
      <path
        d="M5.25 4.25V3.5A1.75 1.75 0 0 1 7 1.75h5.5a1.75 1.75 0 0 1 1.75 1.75V9A1.75 1.75 0 0 1 12.5 10.75h-.75"
        stroke="currentColor"
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.5"
      />
      <rect
        height="9"
        rx="1.75"
        stroke="currentColor"
        strokeWidth="1.5"
        width="9"
        x="1.75"
        y="5.25"
      />
    </svg>
  );
}

function CheckIcon({ className }: { className?: string }) {
  return (
    <svg
      aria-hidden="true"
      className={className}
      fill="none"
      viewBox="0 0 16 16"
    >
      <path
        d="m3.25 8.25 3 3 6.5-6.5"
        stroke="currentColor"
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.75"
      />
    </svg>
  );
}

async function writeClipboardText(value: string) {
  if (navigator.clipboard?.writeText) {
    await navigator.clipboard.writeText(value);
    return;
  }

  const textarea = document.createElement("textarea");
  textarea.value = value;
  textarea.setAttribute("readonly", "");
  textarea.style.position = "fixed";
  textarea.style.top = "0";
  textarea.style.left = "-9999px";
  document.body.appendChild(textarea);
  textarea.select();

  try {
    document.execCommand("copy");
  } finally {
    document.body.removeChild(textarea);
  }
}

function CodeCopyButton({
  className,
  copiedLabel = "Copied",
  copyLabel = "Copy code",
  disabled,
  onClick,
  placement = "block",
  timeout = 1600,
  value,
  ...props
}: CodeCopyButtonProps) {
  const [copied, setCopied] = React.useState(false);
  const timeoutRef = React.useRef<number | null>(null);
  const iconClassName = placement === "inline" ? "size-[0.9em]" : "size-3.5";

  React.useEffect(() => {
    return () => {
      if (timeoutRef.current) {
        window.clearTimeout(timeoutRef.current);
      }
    };
  }, []);

  async function handleClick(event: React.MouseEvent<HTMLButtonElement>) {
    onClick?.(event);

    if (event.defaultPrevented || disabled) return;

    await writeClipboardText(value);
    setCopied(true);

    if (timeoutRef.current) {
      window.clearTimeout(timeoutRef.current);
    }

    timeoutRef.current = window.setTimeout(() => {
      setCopied(false);
      timeoutRef.current = null;
    }, timeout);
  }

  return (
    <button
      type="button"
      aria-label={copied ? copiedLabel : copyLabel}
      className={cn(
        [
          "inline-flex shrink-0 items-center justify-center rounded-md",
          "text-neutral-500 outline-none transition-[background-color,color,opacity,transform] duration-150",
          "hover:bg-neutral-950/5 hover:text-foreground active:scale-95",
          "focus-visible:ring-2 focus-visible:ring-current/25",
          "disabled:pointer-events-none disabled:opacity-50",
          "dark:text-neutral-400 dark:hover:bg-white/10 dark:hover:text-white",
          placement === "block"
            ? "absolute right-2 top-2 size-7 bg-white/80 shadow-sm backdrop-blur dark:bg-neutral-950/75"
            : "size-[1.45em] rounded-[0.325em] bg-transparent",
        ],
        className,
      )}
      data-copied={copied ? "" : undefined}
      disabled={disabled}
      onClick={handleClick}
      title={copied ? copiedLabel : copyLabel}
      {...props}
    >
      {copied ? (
        <CheckIcon className={iconClassName} />
      ) : (
        <CopyIcon className={iconClassName} />
      )}
    </button>
  );
}

export { CodeCopyButton };
